const getBackendUrl = (): string =>
  process.env.REACT_APP_BACKEND_URL || 'http://localhost:3101';

async function request<T>(
  path: string,
  options: RequestInit = {},
): Promise<T> {
  const res = await fetch(`${getBackendUrl()}${path}`, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...options.headers,
    },
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(`API ${res.status}: ${text}`);
  }
  return res.json();
}

function authHeaders(sessionToken: string): HeadersInit {
  return { Authorization: `Bearer ${sessionToken}` };
}

// ---------- Auth ----------

export async function exchangeLoginToken(
  token: string,
): Promise<{ sessionToken: string; userId: number }> {
  return request('/api/auth/exchange', {
    method: 'POST',
    body: JSON.stringify({ token }),
  });
}

export async function getEphemeralToken(
  sessionToken: string,
): Promise<{ token: string; expiresAt: string }> {
  return request('/api/token', {
    headers: authHeaders(sessionToken),
  });
}

