import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { GenAILiveClient } from "../lib/genai-live-client";
import { LiveClientOptions } from "../types";
import { AudioStreamer } from "../lib/audio-streamer";
import { audioContext } from "../lib/utils";
import VolMeterWorket from "../lib/worklets/vol-meter";
import { LiveConnectConfig, Modality } from "@google/genai";
import { useLoggerStore } from "../lib/store-logger";

export type UseLiveAPIResults = {
  client: GenAILiveClient;
  setConfig: (config: LiveConnectConfig) => void;
  config: LiveConnectConfig;
  connected: boolean;
  status: "connected" | "disconnected" | "connecting";
  lastError: string | null;
  connect: () => Promise<void>;
  disconnect: () => Promise<void>;
  volume: number;
};

const DEFAULT_CONFIG: LiveConnectConfig = {
  responseModalities: [Modality.AUDIO],
  systemInstruction: "You are a helpful eBay selling assistant.", // Phase 2: full prompt
  tools: [],
  inputAudioTranscription: {},
  outputAudioTranscription: {},
};

export function useLiveAPI(
  options: LiveClientOptions | null,
  model: string,
): UseLiveAPIResults {
  const client = useMemo(
    () => (options ? new GenAILiveClient(options) : null),
    [options],
  );
  const audioStreamerRef = useRef<AudioStreamer | null>(null);
  const pushLog = useLoggerStore((state) => state.log);
  const clearLogs = useLoggerStore((state) => state.clearLogs);

  const [config, setConfig] = useState<LiveConnectConfig>(DEFAULT_CONFIG);
  const [connected, setConnected] = useState(false);
  const [status, setStatus] = useState<"connected" | "disconnected" | "connecting">("disconnected");
  const [lastError, setLastError] = useState<string | null>(null);
  const [volume, setVolume] = useState(0);

  // register audio for streaming server -> speakers
  useEffect(() => {
    if (!audioStreamerRef.current) {
      audioContext({ id: "audio-out" }).then((audioCtx: AudioContext) => {
        audioStreamerRef.current = new AudioStreamer(audioCtx);
        audioStreamerRef.current
          .addWorklet<any>("vumeter-out", VolMeterWorket, (ev: any) => {
            setVolume(ev.data.volume);
          })
          .then(() => {
            // Successfully added worklet
          });
      });
    }
  }, [audioStreamerRef]);

  useEffect(() => {
    if (!client) return;

    const onOpen = () => {
      setConnected(false);
      setStatus("connecting");
    };
    const onClose = () => {
      setConnected(false);
      setStatus("disconnected");
    };
    const onError = (error: ErrorEvent) => {
      console.error("error", error);
      setLastError(error.message || "Live API connection failed");
      setStatus("disconnected");
    };
    const stopAudioStreamer = () => audioStreamerRef.current?.stop();
    const onAudio = (data: ArrayBuffer) =>
      audioStreamerRef.current?.addPCM16(new Uint8Array(data));
    const onLog = (log: Parameters<typeof pushLog>[0]) => pushLog(log);
    const onSetupComplete = () => {
      setConnected(true);
      setStatus("connected");
      setLastError(null);
    };

    client
      .on("log", onLog)
      .on("error", onError)
      .on("open", onOpen)
      .on("close", onClose)
      .on("setupcomplete", onSetupComplete)
      .on("interrupted", stopAudioStreamer)
      .on("audio", onAudio);

    return () => {
      client
        .off("log", onLog)
        .off("error", onError)
        .off("open", onOpen)
        .off("close", onClose)
        .off("setupcomplete", onSetupComplete)
        .off("interrupted", stopAudioStreamer)
        .off("audio", onAudio)
        .disconnect();
    };
  }, [client, pushLog]);

  const connect = useCallback(async () => {
    if (!client || !config) {
      throw new Error("client or config not ready");
    }
    clearLogs();
    setLastError(null);
    setStatus("connecting");
    client.disconnect();
    const didConnect = await client.connect(model, config);
    if (!didConnect) {
      setStatus("disconnected");
      setLastError("Live API connection did not open. Check browser console and permissions.");
    }
  }, [client, config, model, clearLogs]);

  const disconnect = useCallback(async () => {
    client?.disconnect();
    setConnected(false);
    setStatus("disconnected");
  }, [setConnected, client]);

  // Return a stub when client is not ready yet
  const stub = useMemo<UseLiveAPIResults>(
    () => ({
      client: null as any,
      config,
      setConfig,
      connected: false,
      status: "disconnected",
      lastError: null,
      connect: async () => {},
      disconnect: async () => {},
      volume: 0,
    }),
    [config],
  );

  if (!client) return stub;

  return {
    client,
    config,
    setConfig,
    connected,
    status,
    lastError,
    connect,
    disconnect,
    volume,
  };
}
