import { useMemo, useRef, useState } from "react";
import "./App.scss";
import { LiveAPIProvider } from "./contexts/LiveAPIContext";
import { useLiveAPIContext } from "./contexts/LiveAPIContext";
import ControlTray from "./components/control-tray/ControlTray";
import AuthGate from "./components/auth-gate/AuthGate";
import Logger from "./components/logger/Logger";
import cn from "classnames";

const GEMINI_MODEL =
  process.env.REACT_APP_GEMINI_MODEL ||
  "gemini-2.5-flash-native-audio-preview-12-2025";

function LiveWorkspace() {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [videoStream, setVideoStream] = useState<MediaStream | null>(null);
  const { connected, status, lastError } = useLiveAPIContext();
  const statusLabel = useMemo(() => {
    if (status === "connected") {
      return "Connected";
    }
    if (status === "connecting") {
      return "Connecting";
    }
    return "Disconnected";
  }, [status]);

  return (
    <div className="streaming-console">
      <main>
        <section className="live-shell">
          <div className="live-shell__stage">
            <div className="live-shell__status-bar">
              <div className={cn("live-shell__badge", `is-${status}`)}>
                {statusLabel}
              </div>
              <p className="live-shell__hint">
                Browser streams directly to Gemini Live after backend login and token exchange.
              </p>
            </div>

            <div className="main-app-area">
              <video
                className={cn("stream", {
                  hidden: !videoRef.current || !videoStream,
                })}
                ref={videoRef}
                autoPlay
                playsInline
              />
              {!videoStream && (
                <div className="live-shell__empty-state">
                  <h2>Live agent console</h2>
                  <p>1. Grant microphone access.</p>
                  <p>2. Click play to open the Gemini Live session.</p>
                  <p>3. Optional: turn on webcam or screen share.</p>
                </div>
              )}
            </div>

            <ControlTray
              videoRef={videoRef}
              supportsVideo={true}
              onVideoStreamChange={setVideoStream}
            />
          </div>

          <aside className="live-shell__sidebar">
            <section className="live-shell__panel">
              <h3>Session</h3>
              <p>Status: {statusLabel}</p>
              <p>Audio: {connected ? "streaming enabled" : "idle"}</p>
              {lastError && <p className="live-shell__error">Error: {lastError}</p>}
            </section>

            <section className="live-shell__panel live-shell__panel--logs">
              <h3>Live logs</h3>
              <Logger filter="none" />
            </section>
          </aside>
        </section>
      </main>
    </div>
  );
}

function App() {
  return (
    <div className="App">
      <AuthGate>
        <LiveAPIProvider model={GEMINI_MODEL}>
          <LiveWorkspace />
        </LiveAPIProvider>
      </AuthGate>
    </div>
  );
}

export default App;
